     1→import {
     2→  access,
     3→  cp,
     4→  lstat,
     5→  mkdir,
     6→  realpath,
     7→  rename,
     8→  rm,
     9→  symlink,
    10→  unlink,
    11→} from "node:fs/promises";
    12→import path from "node:path";
    13→import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
    14→import { UserError } from "../errors.ts";
    15→import { logger } from "../logger.ts";
    16→import type {
    17→  AgentId,
    18→  DeployAction,
    19→  Manifest,
    20→  SkillDirDeployAction,
    21→} from "../types.ts";
    22→import { registerDeployment, verifyDeployment } from "./ownership.ts";
    23→import { getDeployMethod, resolveAgentSkillPath } from "./resolve.ts";
    24→
    25→function sourceAccessError(err: unknown, sourcePath: string): string {
    26→  const code = (err as NodeJS.ErrnoException).code;
    27→  if (code === "ENOENT") return `Source not found: ${sourcePath}`;
    28→  if (code === "EACCES" || code === "EPERM")
    29→    return `Permission denied accessing source: ${sourcePath}`;
    30→  const detail = err instanceof Error ? err.message : String(err);
    31→  return `Failed to access source ${sourcePath}: ${detail}`;
    32→}
    33→
    34→export async function planDeploy(
    35→  manifest: Manifest,
    36→  sourceDir: string,
    37→  detectedAgents: AgentId[],
    38→  home: string,
    39→): Promise<DeployAction[]> {
    40→  const method = getDeployMethod();
    41→  const actions: DeployAction[] = [];
    42→  const resolvedSourceDir = path.resolve(sourceDir);
    43→
    44→  let realRoot: string;
    45→  try {
    46→    realRoot = await realpath(resolvedSourceDir);
    47→  } catch {
    48→    realRoot = resolvedSourceDir;
    49→  }
    50→
    51→  for (const skill of manifest.skills) {
    52→    const source = path.resolve(sourceDir, skill.path);
    53→    await validateSourcePath(source, skill.path, resolvedSourceDir, realRoot);
    54→
    55→    await validateSkillContract(source, skill.path);
    56→
    57→    for (const agentId of skill.agents) {
    58→      if (!detectedAgents.includes(agentId)) continue;
    59→
    60→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    61→      if (!agent) continue;
    62→
    63→      const target = resolveAgentSkillPath(agent, skill.name, home);
    64→
    65→      actions.push({
    66→        kind: "skill-dir",
    67→        skill: skill.name,
    68→        agent: agentId,
    69→        source,
    70→        target,
    71→        method,
    72→      });
    73→    }
    74→  }
    75→
    76→  return actions;
    77→}
    78→
    79→export async function executeDeploy(
    80→  actions: DeployAction[],
    81→  dryRun: boolean,
    82→  verbose: boolean,
    83→  home: string,
    84→): Promise<{
    85→  succeeded: number;
    86→  failed: Array<{ action: DeployAction; error: string }>;
    87→}> {
    88→  let succeeded = 0;
    89→  const failed: Array<{ action: DeployAction; error: string }> = [];
    90→
    91→  for (const action of actions) {
    92→    switch (action.kind) {
    93→      case "skill-dir": {
    94→        const result = await deploySkillDir(action, dryRun, verbose, home);
    95→        if (result.error === null) {
    96→          succeeded++;
    97→        } else {
    98→          failed.push({ action, error: result.error });
    99→        }
   100→        break;
   101→      }
   102→      default: {
   103→        const _: never = action.kind;
   104→        throw new Error(`Unhandled deploy action kind: ${_}`);
   105→      }
   106→    }
   107→  }
   108→
   109→  return { succeeded, failed };
   110→}
   111→
   112→async function deploySkillDir(
   113→  action: SkillDirDeployAction,
   114→  dryRun: boolean,
   115→  verbose: boolean,
   116→  home: string,
   117→): Promise<{ error: string | null }> {
   118→  const label = `${action.skill} -> ${action.agent}`;
   119→
   120→  try {
   121→    await access(action.source);
   122→  } catch (err) {
   123→    const msg = sourceAccessError(err, action.source);
   124→    logger.fail(label, msg);
   125→    return { error: msg };
   126→  }
   127→
   128→  if (dryRun) {
   129→    logger.plan(label);
   130→    if (verbose) {
   131→      logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
   132→    }
   133→    return { error: null };
   134→  }
   135→
   136→  try {
   137→    await executeDeployAction(action, verbose, home);
   138→    return { error: null };
   139→  } catch (err) {
   140→    const msg = err instanceof Error ? err.message : String(err);
   141→    logger.fail(label, msg);
   142→    return { error: msg };
   143→  }
   144→}
   145→
   146→async function validateSourcePath(
   147→  source: string,
   148→  skillPath: string,
   149→  resolvedSourceDir: string,
   150→  realRoot: string,
   151→): Promise<void> {
   152→  if (!source.startsWith(resolvedSourceDir + path.sep)) {
   153→    throw new UserError(
   154→      "DEPLOY_FAILED",
   155→      `Skill path "${skillPath}" resolves outside the repository root: ${source}`,
   156→    );
   157→  }
   158→
   159→  try {
   160→    const realSource = await realpath(source);
   161→    if (
   162→      realSource !== realRoot &&
   163→      !realSource.startsWith(realRoot + path.sep)
   164→    ) {
   165→      throw new UserError(
   166→        "DEPLOY_FAILED",
   167→        `Skill path "${skillPath}" resolves outside the repository root via symlink: ${source} -> ${realSource}`,
   168→      );
   169→    }
   170→  } catch (err) {
   171→    if (err instanceof UserError) throw err;
   172→    // Source doesn't exist yet — will be caught during execute
   173→  }
   174→}
   175→
   176→async function validateSkillContract(
   177→  source: string,
   178→  skillPath: string,
   179→): Promise<void> {
   180→  let stat: import("node:fs").Stats;
   181→  try {
   182→    stat = await lstat(source);
   183→  } catch (err) {
   184→    const code = (err as NodeJS.ErrnoException).code;
   185→    if (code === "ENOENT") {
   186→      throw new UserError(
   187→        "DEPLOY_FAILED",
   188→        `Skill "${skillPath}" source not found: ${source}`,
   189→      );
   190→    }
   191→    if (code === "EACCES" || code === "EPERM") {
   192→      throw new UserError(
   193→        "DEPLOY_FAILED",
   194→        `Permission denied accessing skill "${skillPath}" source: ${source}`,
   195→      );
   196→    }
   197→    throw new UserError(
   198→      "DEPLOY_FAILED",
   199→      `Cannot access skill "${skillPath}" source: ${source}`,
   200→    );
   201→  }
   202→  if (!stat.isDirectory()) {
   203→    throw new UserError(
   204→      "DEPLOY_FAILED",
   205→      `Skill "${skillPath}" source is not a directory: ${source}`,
   206→    );
   207→  }
   208→  try {
   209→    await access(path.join(source, "SKILL.md"));
   210→  } catch {
   211→    throw new UserError(
   212→      "DEPLOY_FAILED",
   213→      `Skill "${skillPath}" source is missing SKILL.md: ${source}`,
   214→    );
   215→  }
   216→}
   217→
   218→async function assertTargetAbsent(targetPath: string): Promise<void> {
   219→  try {
   220→    await lstat(targetPath);
   221→    throw new Error(
   222→      `Target path appeared unexpectedly after backup: ${targetPath}`,
   223→    );
   224→  } catch (err) {
   225→    if (err instanceof Error && err.message.startsWith("Target path appeared"))
   226→      throw err;
   227→    // ENOENT is expected — target should not exist after backup
   228→  }
   229→}
   230→
   231→async function createDeployTarget(
   232→  action: DeployAction,
   233→  home: string,
   234→): Promise<void> {
   235→  if (action.method === "symlink") {
   236→    await symlink(action.source, action.target, "dir");
   237→  } else {
   238→    await cp(action.source, action.target, { recursive: true });
   239→  }
   240→  await registerDeployment(home, action.target, {
   241→    source: action.source,
   242→    skill: action.skill,
   243→    agent: action.agent,
   244→    method: action.method,
   245→  });
   246→}
   247→
   248→async function executeDeployAction(
   249→  action: DeployAction,
   250→  verbose: boolean,
   251→  home: string,
   252→): Promise<void> {
   253→  const label = `${action.skill} -> ${action.agent}`;
   254→  const backupPath = await backupExisting(action.target, verbose, home, {
   255→    source: action.source,
   256→    skill: action.skill,
   257→    agent: action.agent,
   258→  });
   259→  await mkdir(path.dirname(action.target), { recursive: true });
   260→
   261→  try {
   262→    await assertTargetAbsent(action.target);
   263→    await createDeployTarget(action, home);
   264→  } catch (createErr) {
   265→    if (backupPath) {
   266→      try {
   267→        await rename(backupPath, action.target);
   268→      } catch {
   269→        // Best-effort rollback
   270→      }
   271→    }
   272→    throw createErr;
   273→  }
   274→
   275→  if (backupPath) {
   276→    await removeTarget(backupPath);
   277→  }
   278→
   279→  logger.ok(label);
   280→  if (verbose) {
   281→    logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
   282→  }
   283→}
   284→
   285→async function backupExisting(
   286→  targetPath: string,
   287→  verbose: boolean,
   288→  home: string,
   289→  expected: { source: string; skill: string; agent: AgentId },
   290→): Promise<string | null> {
   291→  try {
   292→    await lstat(targetPath);
   293→  } catch {
   294→    return null;
   295→  }
   296→
   297→  if (!(await verifyDeployment(home, targetPath, expected))) {
   298→    throw new Error(
   299→      `Target "${targetPath}" exists but is not managed by inception-engine — refusing to overwrite`,
   300→    );
   301→  }
   302→
   303→  const backupPath = `${targetPath}.inception-backup`;
   304→
   305→  // Clean up any stale backup from a previous failed attempt
   306→  try {
   307→    await lstat(backupPath);
   308→    await removeTarget(backupPath);
   309→  } catch {
   310→    // No stale backup — expected
   311→  }
   312→
   313→  if (verbose) {
   314→    logger.detail(`backing up existing target: ${targetPath}`);
   315→  }
   316→
   317→  await rename(targetPath, backupPath);
   318→  return backupPath;
   319→}
   320→
   321→async function removeTarget(targetPath: string): Promise<void> {
   322→  const stat = await lstat(targetPath);
   323→  if (stat.isSymbolicLink()) {
   324→    await unlink(targetPath);
   325→  } else {
   326→    await rm(targetPath, { recursive: true });
   327→  }
   328→}
   329→

