          assert.match(err.message, /resolves outside the repository root/);
          return true;
        },
      );
    } finally {
      rmSync(sourceDir, { recursive: true });
    }
  });

  it("throws when skill.path escapes sourceDir via traversal (../../outside)", async () => {
